const raw = $json ?? {};
const userInput = typeof raw.userInput === 'string' ? raw.userInput.trim() : '';
if (!userInput) {
  throw new Error('AISMR workflow requires a non-empty userInput string.');
}
const nowIso = new Date().toISOString();
const sessionId = raw.sessionId && typeof raw.sessionId === 'string' && raw.sessionId.trim().length > 0
  ? raw.sessionId.trim()
  : `aismr:${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
const personaId = typeof raw.personaId === 'string' && raw.personaId.trim().length > 0 ? raw.personaId.trim() : 'ideagenerator';
const projectId = typeof raw.projectId === 'string' && raw.projectId.trim().length > 0 ? raw.projectId.trim() : 'aismr';
const outputSchema = {
  type: 'object',
  properties: {
    userIdea: {
      type: 'string',
      description: 'Normalized base object (lowercase singular) applied to every idea.'
    },
    ideas: {
      type: 'array',
      description: 'Exactly 12 unique AISMR-ready concepts in Title Case descriptor + singular object format.',
      items: {
        type: 'object',
        properties: {
          idea: {
            type: 'string',
            description: 'Title Case descriptor + singular object (two words, descriptor is one word).'
          },
          vibe: {
            type: 'string',
            description: '2-4 sentence explanation covering emotion, hook, texture, feasibility, replay value, and environment potential.'
          }
        },
        required: ['idea', 'vibe'],
        additionalProperties: false
      },
      minItems: 12,
      maxItems: 12
    }
  },
  required: ['userIdea', 'ideas'],
  additionalProperties: false
};
return {
  json: {
    userInput,
    sessionId,
    personaId,
    projectId,
    outputSchema: JSON.stringify(outputSchema),
    timestamps: {
      receivedAt: nowIso
    },
    userId: raw.userId ?? null,
  },
};

const normalized = $('Normalize Request').item?.json ?? {};
const sessionId = typeof normalized.sessionId === 'string' ? normalized.sessionId.trim() : '';
const content = typeof normalized.userInput === 'string' ? normalized.userInput.trim() : '';
const timestamp = normalized.timestamps?.receivedAt ?? new Date().toISOString();

const metadata = {
  workflow: 'aismr',
  persona: normalized.personaId,
  project: normalized.projectId,
  timestamp,
};

const payload = sessionId && content
  ? {
      sessionId,
      role: 'user',
      content,
      metadata,
      embeddingText: content,
      userId: normalized.userId ?? null,
    }
  : null;

return {
  json: {
    ...normalized,
    conversationStorePayload: payload,
  },
};

const normalized = $('Normalize Request').item?.json ?? {};
const payload = {
  projectId: normalized.projectId,
  personaId: normalized.personaId,
  chatInput: normalized.userInput,
  outputSchema: normalized.outputSchema,
  sessionId: normalized.sessionId,
};
return { json: payload };

function tryParse(value) {
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch (error) {
      return null;
    }
  }
  return null;
}

function extractStructured(value) {
  if (value == null) {
    return null;
  }
  if (typeof value === 'string') {
    const parsed = tryParse(value);
    if (parsed) {
      return extractStructured(parsed);
    }
    return null;
  }
  if (Array.isArray(value)) {
    for (const item of value) {
      const extracted = extractStructured(item);
      if (extracted) return extracted;
    }
    return null;
  }
  if (typeof value === 'object') {
    if (typeof value.userIdea === 'string' && Array.isArray(value.ideas)) {
      return value;
    }
    const candidates = [value.output, value.result, value.structuredOutput, value.data, value.response, value.content];
    for (const candidate of candidates) {
      const extracted = extractStructured(candidate);
      if (extracted) return extracted;
    }
  }
  return null;
}

const original = $json ?? {};
if (original.error) {
  const reason = typeof original.error === 'object' ? (original.error.message || original.error.reason || JSON.stringify(original.error)) : String(original.error);
  throw new Error(`Mylo MCP Bot failed: ${reason}`);
}

const structured = extractStructured(original);
if (!structured) {
  throw new Error('AISMR Mylo response did not include structured output.');
}
if (typeof structured.userIdea !== 'string' || structured.userIdea.trim().length === 0) {
  throw new Error('AISMR Mylo response missing userIdea string.');
}
if (!Array.isArray(structured.ideas) || structured.ideas.length !== 12) {
  throw new Error('AISMR Mylo response must contain exactly 12 ideas.');
}
structured.ideas.forEach((idea, index) => {
  if (!idea || typeof idea !== 'object') {
    throw new Error(`Idea #${index + 1} is not an object.`);
  }
  if (typeof idea.idea !== 'string' || idea.idea.trim().length === 0) {
    throw new Error(`Idea #${index + 1} missing idea text.`);
  }
  if (typeof idea.vibe !== 'string' || idea.vibe.trim().length === 0) {
    throw new Error(`Idea #${index + 1} missing vibe text.`);
  }
});

const normalized = $('Normalize Request').item?.json ?? {};
const rawResponse = JSON.stringify(structured, null, 2);
const sessionId = normalized.sessionId ?? null;
const timestamp = new Date().toISOString();

const conversationStorePayload = {
  sessionId,
  role: 'assistant',
  content: rawResponse,
  userId: normalized.userId ?? null,
  metadata: {
    workflow: 'aismr',
    persona: normalized.personaId,
    project: normalized.projectId,
    ideaCount: structured.ideas.length,
    userIdea: structured.userIdea,
    generatedAt: timestamp,
  },
  embeddingText: rawResponse,
};

return {
  json: {
    sessionId,
    userIdea: structured.userIdea,
    ideas: structured.ideas,
    rawResponse,
    conversationStorePayload,
    telemetry: {
      myloResponse: original,
    },
  },
};

const response = $('Prepare Response').item?.json ?? {};
const assistantStore = $json ?? {};
const userStore = $('Store User Turn').item?.json ?? {};

return {
  json: {
    sessionId: response.sessionId ?? null,
    userIdea: response.userIdea,
    ideas: response.ideas,
    rawResponse: response.rawResponse,
    telemetry: {
      myloResponse: response.telemetry?.myloResponse ?? null,
      userStore,
      assistantStore,
    },
  },
};
